].[GETALL_VT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC XOA_TK 'luan';\r\n--DROP PROC  XOA_TK;\r\n\r\n\r\n--Bảng Vaitro\r\nCREATE PROC [dbo].[GETALL_VT]    \r\nAS\r\nBEGIN \r\n   SELECT*FROM vaitro\r\n   \r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='GETALL_VT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_CT]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_CT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_CT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROC [dbo].[INSERT_CT]\n@taikhoan NVARCHAR(100),\n@thongtin NVARCHAR(MAX),\n@loaithaotac NVARCHAR(50),\n@chitiet NVARCHAR(MAX),\n@trangthai NVARCHAR(50),\n@ngay DATETIME = NULL \nAS\nBEGIN\n    IF @ngay IS NULL\n        SET @ngay = GETDATE()\n    \n    INSERT INTO chitietthaotac (taikhoan, thongtin, loaithaotac, chitiet, trangthai, ngay)\n    VALUES (@taikhoan, @thongtin, @loaithaotac, @chitiet, @trangthai, @ngay)\nEND\n\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_CT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_QH]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_QH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_QH]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROC [dbo].[INSERT_QH]\r\n    @tenqh NVARCHAR(255),\r\n    @idtinh INT\r\nAS\r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM quan_huyen WHERE tenqh = @tenqh AND idtinh = @idtinh)\r\n    BEGIN\r\n        INSERT INTO quan_huyen (tenqh, idtinh) VALUES (@tenqh, @idtinh)\r\nEND\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_QH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_TINH]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_TINH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_TINH]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n\r\nCREATE PROC [dbo].[INSERT_TINH]\r\n    @ten NVARCHAR(255)\r\nAS\r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM tinh_tp WHERE ten = @ten)\r\n\tBEGIN\r\n    INSERT INTO tinh_tp (ten) VALUES (@ten)\r\n\tEND\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_TINH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_UPDATE_PQ]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_UPDATE_PQ' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_UPDATE_PQ]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROC [dbo].[INSERT_UPDATE_PQ]\r\n    @idus INT,\r\n    @idvt INT,\r\n    @role BIT,\r\n    @trangthai BIT = 0\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n    IF EXISTS (SELECT 1 FROM users WHERE idus = @idus) AND EXISTS (SELECT 1 FROM vaitro WHERE idvt = @idvt)\r\n    BEGIN\r\n  \r\n        IF EXISTS (SELECT 1 FROM dmphanquyen WHERE idus = @idus AND idvt = @idvt)\r\n        BEGIN           \r\n            UPDATE dmphanquyen\r\n            SET role = @role, trangthai = @trangthai\r\n            WHERE idus = @idus AND idvt = @idvt       \r\n        END\r\n        ELSE\r\n        BEGIN           \r\n            INSERT INTO dmphanquyen (idus, idvt, role, trangthai)\r\n            VALUES (@idus, @idvt, @role, @trangthai);\r\n           \r\n        END\r\n    END\r\n    \r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_UPDATE_PQ' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_US]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_US' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_US]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC GETALL_PQ;\r\n\r\n\r\nCREATE PROC [dbo].[INSERT_US]   \r\n    @idpb INT,  \r\n    @hoten NVARCHAR(255),\r\n    @ngaysinh DATE,\r\n    @diachi NVARCHAR(255),\r\n    @sodienthoai NVARCHAR(12),\r\n    @email NVARCHAR(100),\r\n    @gioitinh BIT,\r\n    @chucvu NVARCHAR(20)\t\r\nAS\r\nBEGIN\r\n    INSERT INTO users (idpb, hoten, ngaysinh, diachi, sodienthoai, email, gioitinh, chucvu)\r\n    VALUES (@idpb, @hoten, @ngaysinh, @diachi, @sodienthoai, @email, @gioitinh, @chucvu)   \r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_US' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_VT]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_VT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_VT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC GETALL_VT;\r\n--DROP PROC GETALLVT;\r\n\r\nCREATE PROC [dbo].[INSERT_VT]\r\n    @tenvaitro NVARCHAR(50),\r\n    @trangthai BIT,\r\n    @ghichu NVARCHAR(MAX) = NULL\r\nAS\r\nBEGIN\r\n\t\r\n    INSERT INTO vaitro (tenvaitro, ngaytao, ngaycapnhat, trangthai, ghichu)\r\n    VALUES (@tenvaitro, GETDATE(), GETDATE(), @trangthai, @ghichu)\r\n\t\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_VT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[INSERT_XP]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_XP' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[INSERT_XP]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n\r\nCREATE PROC [dbo].[INSERT_XP]\r\n    @tenxp NVARCHAR(255),\r\n    @idquan INT\r\nAS\r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM xa_phuong WHERE tenxp = @tenxp AND idquan = @idquan)\r\n    BEGIN\r\n        INSERT INTO xa_phuong (tenxp, idquan) VALUES (@tenxp, @idquan)\r\n    END\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='INSERT_XP' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[RESET_TK]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='RESET_TK' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[RESET_TK]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC DOIMK 'hung','hunghung123','hung321';\r\n--DROP PROC DOIMK;\r\n\r\nCREATE PROC [dbo].[RESET_TK]\r\n    @taikhoan NVARCHAR(100),\r\n    @matkhaumoi NVARCHAR(255)\r\nAS\r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM dmtaikhoan WHERE taikhoan= @taikhoan AND trangthai=1)\r\n    BEGIN\r\n        UPDATE dmtaikhoan\r\n        SET matkhau = @matkhaumoi,ngaycapnhat = GETDATE()\r\n        WHERE taikhoan= @taikhoan\r\n    END\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='RESET_TK' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SPLOGIN]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='SPLOGIN' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SPLOGIN]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROC [dbo].[SPLOGIN]\r\n    @taikhoan NVARCHAR(100),\r\n    @matkhau NVARCHAR(255)\r\nAS\r\nBEGIN\r\n    SET NOCOUNT ON;\r\n    IF EXISTS (SELECT 1 FROM dmtaikhoan WHERE taikhoan = @taikhoan AND matkhau = @matkhau)\r\n    BEGIN\r\n        UPDATE dmtaikhoan\r\n\t\tSET trangthai = 1, tglogin =GETDATE()\r\n        WHERE taikhoan = @taikhoan;   \r\n    END\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='SPLOGIN' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[SPLOGOUT]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='SPLOGOUT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[SPLOGOUT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC SPLOGIN 'hau','luan';\r\n\r\n\r\nCREATE PROC [dbo].[SPLOGOUT]\r\n    @taikhoan NVARCHAR(100)\r\nAS\r\nBEGIN \r\n    SET NOCOUNT ON;\r\n    IF EXISTS (SELECT 1 FROM dmtaikhoan WHERE taikhoan = @taikhoan)\r\n    BEGIN      \r\n        UPDATE dmtaikhoan\r\n        SET trangthai = 0, tglogout=GETDATE()\r\n        WHERE taikhoan = @taikhoan;     \r\n       \r\n    END\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='SPLOGOUT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[UPDATE_CT]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_CT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[UPDATE_CT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROC [dbo].[UPDATE_CT]\n@idtc INT,\n@taikhoan NVARCHAR(100),\n@thongtin NVARCHAR(MAX),\n@loaithaotac NVARCHAR(50),\n@chitiet NVARCHAR(MAX),\n@trangthai NVARCHAR(50),\n@ngay DATETIME = NULL \nAS\nBEGIN\n    IF @ngay IS NULL\n        SET @ngay = GETDATE()\n    \n    UPDATE chitietthaotac\n    SET taikhoan = @taikhoan,\n        thongtin = @thongtin,\n        loaithaotac = @loaithaotac,\n        chitiet = @chitiet,\n        trangthai = @trangthai,\n        ngay = @ngay\n    WHERE idtc = @idtc\nEND\n\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_CT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[UPDATE_PQ]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_PQ' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[UPDATE_PQ]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC XOA_PQ 0,0;\r\n--DROP PROC  XOA_PQ;\r\n\r\n\r\nCREATE PROC [dbo].[UPDATE_PQ]\r\n    @idus INT,\r\n    @idvt INT,\r\n    @trangthai BIT,\r\n    @ghichu NVARCHAR(MAX)\r\nAS\r\nBEGIN\r\n IF EXISTS (SELECT 1 FROM dmphanquyen WHERE idus=@idus and idvt=@idvt ) --xem lại\r\nBEGIN\r\n    UPDATE dmphanquyen\r\n    SET trangthai = @trangthai,\r\n        ghichu = @ghichu\r\n     WHERE idus=@idus  and idvt=@idvt\r\nEND\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_PQ' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[UPDATE_QH]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_QH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[UPDATE_QH]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROC [dbo].[UPDATE_QH]\r\n    @idquan INT,\r\n    @tenqh NVARCHAR(255),\r\n    @idtinh INT\r\nAS\r\nBEGIN\r\n    IF EXISTS (SELECT 1 FROM quan_huyen WHERE idquan = @idquan)\r\n    BEGIN\r\n        IF NOT EXISTS (SELECT 1 FROM quan_huyen WHERE tenqh = @tenqh AND idtinh = @idtinh AND idquan != @idquan)\r\n        BEGIN\r\n            UPDATE quan_huyen \r\n            SET tenqh = @tenqh, idtinh = @idtinh \r\n            WHERE idquan = @idquan\r\nEND\r\nEND\r\nEND\r\nGO\r\n"],"metada