= @hoten,\r\n        ngaysinh = @ngaysinh,\r\n        diachi = @diachi,\r\n        sodienthoai = @sodienthoai,\r\n        email = @email,\r\n        gioitinh = @gioitinh,\r\n        chucvu = @chucvu,\r\n        trangthai = @trangthai\r\n    WHERE idus = @idus\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_US' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[UPDATE_VT]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_VT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[UPDATE_VT]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC  XOA_VT 0;\r\n--DROP PROC XOA_VT ;\r\n\r\nCREATE  PROC [dbo].[UPDATE_VT]\r\n    @idvt INT,\r\n    @tenvaitro NVARCHAR(50),\r\n    @trangthai BIT,\r\n    @ghichu NVARCHAR(MAX) = NULL\r\nAS\r\nBEGIN\r\n    IF EXISTS (SELECT 1 FROM vaitro  WHERE idvt = @idvt )\r\n    BEGIN\r\n        UPDATE vaitro\r\n        SET tenvaitro = @tenvaitro,\r\n            ngaycapnhat = GETDATE(),\r\n            trangthai = @trangthai,\r\n            ghichu = @ghichu\r\n         WHERE idvt = @idvt  \r\n    END  \r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_VT' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[UPDATE_XP]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='UPDATE_XP' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[UPDATE_XP]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET Q