 BEGIN\r\n       DELETE FROM quan_huyen WHERE idquan = @idquan\r\nEND\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='XOA_QH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[XOA_TINH]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='XOA_TINH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[XOA_TINH]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROC [dbo].[XOA_TINH]\r\n    @idtinh INT\r\nAS\r\nBEGIN\r\n    IF EXISTS (SELECT 1 FROM tinh_tp WHERE idtinh = @idtinh)\r\n    BEGIN\r\n        DELETE FROM tinh_tp WHERE idtinh = @idtinh\r\nEND\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='XOA_TINH' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[XOA_TK]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='XOA_TK' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[XOA_TK]    Script Date: 3/14/2026 9:48:29 AM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","--EXEC RESET_TK 1,'hung345';\r\n--Drop proc RESETTK;\r\n\r\nCREATE PROC [dbo].[XOA_TK]\r\n    @taikhoan  NVARCHAR(100)\r\nAS\r\nBEGIN\r\n    DELETE FROM dmtaikhoan WHERE taikhoan=@taikhoan\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='MSI\\MSSQLSERVER03']/Database[@Name='GH']/StoredProcedure[@Name='XOA_TK' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[XOA_US]"],"metadata":{"urn":"Server[@Name='MSI\\MSSQL